const fixtures = [
  { test: 'billing refund', subject: 'Refund not received', message: 'My refund is overdue after seven days.' },
  { test: 'technical outage', subject: 'Production login outage', message: 'All users are blocked and cannot sign in.' },
  { test: 'general question', subject: 'Update company name', message: 'Where can I update our company name?' }
];
return fixtures.map((json, index) => ({ json, pairedItem: { item: index } }));

const results = $input.all().map((item, index) => {
  const text = `${item.json.subject || ''} ${item.json.message || ''}`.toLowerCase();
  const category = /refund|invoice|billing|charge/.test(text) ? 'billing' : /outage|blocked|error|cannot sign in/.test(text) ? 'technical' : 'general';
  const priority = /outage|all users|blocked/.test(text) ? 'high' : /refund|overdue/.test(text) ? 'medium' : 'normal';
  const slaHours = priority === 'high' ? 2 : priority === 'medium' ? 8 : 24;
  const nextStep = category === 'billing' ? 'verify_payment_timeline' : category === 'technical' ? 'collect_reproduction_and_status' : 'route_to_support_queue';
  return { json: { test: item.json.test, synthetic: true, category, priority, slaHours, nextStep }, pairedItem: { item: index } };
});
const byTest = Object.fromEntries(results.map(r => [r.json.test, r.json]));
const checks = [
  byTest['billing refund'].category === 'billing' && byTest['billing refund'].priority === 'medium',
  byTest['technical outage'].category === 'technical' && byTest['technical outage'].priority === 'high' && byTest['technical outage'].slaHours === 2,
  byTest['general question'].category === 'general' && byTest['general question'].priority === 'normal'
];
if (checks.some(v => !v)) throw new Error('Support triage Lite assertions failed: ' + JSON.stringify(checks));
return [{ json: { synthetic: true, liteSample: true, passed: checks.length, failed: 0, results: results.map(r => r.json), boundary: 'Manual synthetic demo only; no webhook, credentials, customer data, or help-desk connection.' } }];
